import React, { useState } from 'react';
import API from '../services/api';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import {
  Container,
  Box,
  Typography,
  TextField,
  Button,
  AppBar,
  Toolbar,
  Select,
  MenuItem,
  FormControl,
  InputLabel,
  Alert
} from '@mui/material';

// Re-using the AppHeader from Dashboard for consistency
function AppHeader() {
  const { logout } = useAuth();
  const nav = useNavigate();

  return (
    <AppBar position="static">
      <Toolbar>
        <Typography variant="h6" component="div" sx={{ flexGrow: 1 }}>
          AutoTechnix
        </Typography>
        <Button color="inherit" component={Link} to="/dashboard" sx={{ mr: 2 }}>Dashboard</Button>
        <Button color="inherit" onClick={logout}>Logout</Button>
      </Toolbar>
    </AppBar>
  );
}

export default function AddCar() {
  const [model, setModel] = useState('');
  const [regNo, setRegNo] = useState('');
  const [fuel, setFuel] = useState('Petrol');
  const [year, setYear] = useState('2020');
  const [image, setImage] = useState(null);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const nav = useNavigate();

  async function submit(e) {
    e.preventDefault();
    setError('');
    setSuccess('');
    if (!image) {
      setError('Please select an image for the car.');
      return;
    }
    try {
      const formData = new FormData();
      formData.append('model', model);
      formData.append('regNo', regNo);
      formData.append('fuelType', fuel);
      formData.append('year', year);
      formData.append('image', image);

      await API.post('/cars', formData, {
        headers: { 'Content-Type': 'multipart/form-data' }
      });
      setSuccess('Car added successfully! Redirecting to dashboard...');
      setTimeout(() => nav('/dashboard'), 2000);
    } catch (e) {
      setError('Error adding car. Please try again.');
      console.error(e);
    }
  }

  return (
    <Box sx={{ flexGrow: 1 }}>
      <AppHeader />
      <Container component="main" maxWidth="sm" sx={{ mt: 4, mb: 4 }}>
        <Box
          sx={{
            padding: 4,
            boxShadow: 3,
            borderRadius: 2,
          }}
        >
          <Typography component="h1" variant="h5" sx={{ mb: 3 }}>
            Add a New Car
          </Typography>
          <Box component="form" onSubmit={submit} noValidate>
            <TextField
              margin="normal"
              required
              fullWidth
              label="Car Model (e.g., Toyota Camry)"
              value={model}
              onChange={e => setModel(e.target.value)}
            />
            <TextField
              margin="normal"
              required
              fullWidth
              label="Registration Number"
              value={regNo}
              onChange={e => setRegNo(e.target.value)}
            />
            <TextField
              margin="normal"
              required
              fullWidth
              label="Year"
              type="number"
              value={year}
              onChange={e => setYear(e.target.value)}
            />
            <FormControl fullWidth margin="normal">
              <InputLabel>Fuel Type</InputLabel>
              <Select
                value={fuel}
                label="Fuel Type"
                onChange={e => setFuel(e.target.value)}
              >
                <MenuItem value="Petrol">Petrol</MenuItem>
                <MenuItem value="Diesel">Diesel</MenuItem>
                <MenuItem value="Electric">Electric</MenuItem>
                <MenuItem value="Hybrid">Hybrid</MenuItem>
              </Select>
            </FormControl>

            <Button
              variant="contained"
              component="label"
              fullWidth
              sx={{ mt: 2 }}
            >
              Upload Car Image
              <input
                type="file"
                hidden
                onChange={e => setImage(e.target.files[0])}
              />
            </Button>
            {image && <Typography sx={{mt:1, textAlign: 'center'}}>{image.name}</Typography>}

            {error && <Alert severity="error" sx={{ width: '100%', mt: 2 }}>{error}</Alert>}
            {success && <Alert severity="success" sx={{ width: '100%', mt: 2 }}>{success}</Alert>}

            <Button
              type="submit"
              fullWidth
              variant="contained"
              sx={{ mt: 3, mb: 2, fontSize: '1.1rem' }}
            >
              Add Car to Garage
            </Button>
          </Box>
        </Box>
      </Container>
    </Box>
  );
}
